import{_ as t,c as i,o as e,V as o}from"./chunks/framework.1sOznGPE.js";const O=JSON.parse('{"title":"虚拟DOM的diff算法","description":"","frontmatter":{},"headers":[],"relativePath":"guide/interview/vue/虚拟DOM/虚拟DOM的diff算法.md","filePath":"guide/interview/vue/虚拟DOM/虚拟DOM的diff算法.md","lastUpdated":1719242077000}'),a={name:"guide/interview/vue/虚拟DOM/虚拟DOM的diff算法.md"},r=o('<h1 id="虚拟dom的diff算法" tabindex="-1">虚拟DOM的diff算法 <a class="header-anchor" href="#虚拟dom的diff算法" aria-label="Permalink to &quot;虚拟DOM的diff算法&quot;">​</a></h1><blockquote><p>Diff算法的作用是用来计算出 <strong>Virtual DOM</strong> 中被改变的部分，然后针对该部分进行原生DOM操作，而不用重新渲染整个页面。</p></blockquote><ol><li><p>用 JavaScript 对象结构表示 DOM 树的结构；然后用这个树构建一个真正的 DOM 树，插到文档当中</p></li><li><p>当状态变更的时候，重新构造一棵新的对象树。然后用新的树和旧的树进行比较(diff)，记录两棵树差异</p></li><li><p>把差异更新到真正的DOM树上(patch)，视图就更新了</p></li></ol><p>Virtual DOM因为是纯粹的JS对象，所以操作它会很高效，但是Virtual DOM的变更最终会转换成DOM操作，为了实现高效的DOM操作，一套高效的<strong>虚拟DOM</strong> <strong>diff算法</strong>显得很有必要。</p><p><strong>diff算法</strong>包括一下几个步骤:</p><ul><li>用 JavaScript 对象结构表示 DOM 树的结构；然后用这个树构建一个真正的 DOM 树，插到文</li></ul><p>档当中</p><ul><li>当状态变更的时候，重新构造一棵新的对象树。然后用新的树和旧的树进行比较(diff)，记录两棵树差异</li><li>把2所记录的差异应用到步骤1所构建的真正的DOM树上(patch)，视图就更新了</li></ul><p><strong>diff算法</strong>是通过<strong>同层的树节点</strong>进行比较而非对树进行逐层搜索遍历的方式，所以时间复杂度只有O(n)，是一种相当高效的算法。</p>',9),f=[r];function d(l,n,s,p,_,c){return e(),i("div",null,f)}const M=t(a,[["render",d]]);export{O as __pageData,M as default};
